#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/stat.h>
#include <dirent.h>
#include <time.h>
#include <unistd.h>

#define MAX_PATH 4096
#define MAX_CONTENT 1024

void init_repo() {
    if (mkdir(".minigit", 0755) != 0) {
        perror("Failed to create .minigit");
        exit(1);
    }
    printf("Initialized empty minigit repository\n");
}

void write_log(const char *message) {
    FILE *log = fopen(".minigit/log.txt", "a");
    if (!log) {
        perror("Failed to open log file");
        exit(1);
    }
    time_t now = time(NULL);
    fprintf(log, "%ld %s\n", now, message);
    fclose(log);
}

void commit(const char *message) {
    char path[MAX_PATH];
    snprintf(path, sizeof(path), ".minigit/%ld.txt", (long)time(NULL));
    FILE *f = fopen(path, "w");
    if (!f) {
        perror("Failed to create commit file");
        exit(1);
    }
    fprintf(f, "%s\n", message);
    fclose(f);
    write_log(message);
    printf("Committed: %s\n", message);
}

void log_commits() {
    FILE *log = fopen(".minigit/log.txt", "r");
    if (!log) {
        printf("No commits yet\n");
        return;
    }
    char line[MAX_CONTENT];
    while (fgets(line, sizeof(line), log)) {
        long ts;
        char msg[MAX_CONTENT];
        if (sscanf(line, "%ld %s", &ts, msg) == 2) {
            printf("%ld %s\n", ts, msg);
        }
    }
    fclose(log);
}

int main(int argc, char *argv[]) {
    if (argc < 2) {
        fprintf(stderr, "Usage: %s <command> [args]\n", argv[0]);
        return 1;
    }

    if (strcmp(argv[1], "init") == 0) {
        init_repo();
    } else if (strcmp(argv[1], "commit") == 0) {
        if (argc < 3) {
            fprintf(stderr, "Usage: %s commit <message>\n", argv[0]);
            return 1;
        }
        if (access(".minigit", F_OK) != 0) {
            fprintf(stderr, "Not a minigit repository\n");
            return 1;
        }
        commit(argv[2]);
    } else if (strcmp(argv[1], "log") == 0) {
        if (access(".minigit", F_OK) != 0) {
            fprintf(stderr, "Not a minigit repository\n");
            return 1;
        }
        log_commits();
    } else {
        fprintf(stderr, "Unknown command: %s\n", argv[1]);
        return 1;
    }

    return 0;
}
